pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract NFTStaking is ReentrancyGuard {
    struct NftStakedData {
        uint256 tokenId;
        uint256 stakedAt;
        uint256 rewardDue;
    }

    IERC721 public nftToken;
    uint256 public tokenRewardInOneHour = 1 ether; // Example reward rate
    uint256 public minimumTimeForUnstake = 24 hours; // Minimum time for unstaking

    mapping(address => bool) public isNftStakedByUser;
    mapping(uint256 => NftStakedData) public nftStakedData;

    event nftStakedEvent(address indexed user, uint256 tokenId);
    event nftUnStakedEvent(address indexed user, uint256 tokenId, uint256 reward);

    constructor(address _nftAddress) {
        nftToken = IERC721(_nftAddress);
    }

    function stakeNFT(uint256 tokenId) external nonReentrant {
        require(nftToken.ownerOf(tokenId) == msg.sender, "Not the owner of the NFT");
        require(!isNftStakedByUser[msg.sender], "Already staked");

        nftStakedData[tokenId] = NftStakedData({
            tokenId: tokenId,
            stakedAt: block.timestamp,
            rewardDue: 0
        });

        isNftStakedByUser[msg.sender] = true;
        require(nftToken.transferFrom(msg.sender, address(this), tokenId), "Transfer failed");

        emit nftStakedEvent(msg.sender, tokenId);
    }

    function unStakeNFT(uint256 tokenId) external nonReentrant {
        require(isNftStakedByUser[msg.sender], "No NFT staked");
        require(nftStakedData[tokenId].tokenId == tokenId, "Invalid tokenId");

        NftStakedData storage stakedData = nftStakedData[tokenId];
        uint256 reward = calculateReward(stakedData.stakedAt);
        stakedData.rewardDue = 0;
        delete nftStakedData[tokenId];

        isNftStakedByUser[msg.sender] = false;
        require(nftToken.transferFrom(address(this), msg.sender, tokenId), "Transfer failed");

        payable(msg.sender).transfer(reward);

        emit nftUnStakedEvent(msg.sender, tokenId, reward);
    }

    function claimReward() external nonReentrant {
        require(isNftStakedByUser[msg.sender], "No NFT staked");

        uint256 tokenId = getStakedTokenId(msg.sender);
        uint256 reward = calculateReward(tokenId);

        require(reward > 0, "No reward available");

        nftStakedData[tokenId].rewardDue += reward;
        nftStakedData[tokenId].stakedAt = block.timestamp;

        payable(msg.sender).transfer(reward);
    }

    function calculateReward(uint256 tokenId) internal view returns (uint256) {
        NftStakedData storage stakedData = nftStakedData[tokenId];
        uint256 stakedTime = block.timestamp - stakedData.stakedAt;
        return (stakedTime / 3600) * tokenRewardInOneHour + stakedData.rewardDue;
    }

    function getStakedTokenId(address user) internal view returns (uint256) {
        for (uint256 i = 0; i < nftToken.balanceOf(user); i++) {
            uint256 tokenId = nftToken.tokenOfOwnerByIndex(user, i);
            if (nftStakedData[tokenId].tokenId != 0) {
                return tokenId;
            }
        }
        revert("No staked NFT found");
    }
}
